sql:
SELECT DISTINCT distance
FROM races
WHERE race_start_time > '17:00:00';

SELECT race.race_id, purse.total_purse
FROM races AS race
JOIN purses AS purse ON race.race_id = purse.race_id;

SELECT AVG(CAST(REPLACE(trim(total_purse, '$'), ',', '') AS REAL)) AS Average_Purse 
FROM purses 
WHERE CAST(REPLACE(trim(total_purse, '$'), ',', '') AS REAL) > 200000;

SELECT race_id, date, purse
FROM races
WHERE purse > (SELECT AVG(purse) FROM races);

SELECT (COUNT(CASE WHEN CAST(SUBSTR(p.total_purse, 2) AS REAL) > 100000 AND p.sponsor = 'XYZ Inc' THEN 1 END) * 100.0 / COUNT(*)) AS percentage_races
FROM races r
INNER JOIN purses p ON r.race_id = p.race_id;

SELECT horse_name
FROM participants
WHERE horse_id NOT IN (
    SELECT horse_id
    FROM results
);

external_knowledge:
- "Particular event" refers to a specific race identified by a unique `race_id`.;
- "Total money bet" indicates the sum of all bets placed on the event. ;
- "Average bet per participant" is calculated as the total bet amount divided by the number of distinct users who bet on the event. ;
- "Number of unique bettors" represents the count of distinct users who placed bets on the event. ;

Top bettors refers to users who have placed the highest total amount of bets;
Kentucky area means tracks located in Kentucky are the only ones considered for the bet records;
The top 10 bettors are those with the highest total bet amounts after sorting by this metric.

